// Collect items from ALL 10 RSS feeds
const allItems = [];

const feeds = [
  { name: 'RSS n8n Blog', source: 'n8n', weight: 10 },
  { name: 'RSS Anthropic', source: 'Anthropic', weight: 9 },
  { name: 'RSS LangChain', source: 'LangChain', weight: 9 },
  { name: 'RSS OpenAI', source: 'OpenAI', weight: 10 },
  { name: 'RSS Zapier', source: 'Zapier', weight: 8 },
  { name: 'RSS Make', source: 'Make', weight: 8 },
  { name: 'RSS Latent Space', source: 'Latent Space', weight: 9 },
  { name: 'RSS Simon Willison', source: 'Simon Willison', weight: 8 },
  { name: 'RSS Hacker News AI', source: 'Hacker News', weight: 7 },
  { name: 'RSS TechCrunch AI', source: 'TechCrunch', weight: 7 }
];

// Keywords that boost relevance score
const hotKeywords = [
  'automation', 'workflow', 'agent', 'agents', 'ai agent',
  'n8n', 'zapier', 'make', 'integromat', 'gohighlevel',
  'claude', 'gpt-4', 'gpt4', 'chatgpt', 'openai',
  'langchain', 'llm', 'api', 'no-code', 'nocode', 'low-code',
  'productivity', 'saas', 'startup', 'founder', 'agency',
  'automate', 'integration', 'crm', 'lead', 'sales',
  'prompt', 'embedding', 'vector', 'rag', 'fine-tune'
];

for (const feed of feeds) {
  try {
    const items = $(feed.name).all();
    items.forEach(item => {
      if (item.json.title) {
        const title = (item.json.title || '').toLowerCase();
        const content = (item.json.contentSnippet || item.json.description || '').toLowerCase();
        const combined = title + ' ' + content;

        // Calculate relevance score
        let relevanceScore = feed.weight;

        for (const keyword of hotKeywords) {
          if (combined.includes(keyword)) {
            relevanceScore += 2;
          }
        }

        // Boost for action words
        if (combined.includes('how to')) relevanceScore += 3;
        if (combined.includes('guide')) relevanceScore += 2;
        if (combined.includes('tutorial')) relevanceScore += 2;
        if (combined.includes('new')) relevanceScore += 1;
        if (combined.includes('launch')) relevanceScore += 2;
        if (combined.includes('release')) relevanceScore += 2;

        allItems.push({
          title: item.json.title || '',
          content: (item.json.contentSnippet || item.json.description || '')
            .replace(/<[^>]*>/g, '')
            .slice(0, 1000),
          source: feed.source,
          link: item.json.link || item.json.url || '',
          pubDate: item.json.pubDate || item.json.isoDate || '',
          relevanceScore: relevanceScore
        });
      }
    });
  } catch(e) {
    // Feed failed, continue with others
  }
}

if (allItems.length === 0) {
  return [{ json: { error: 'No RSS items found from any feed' } }];
}

// Sort by relevance score (highest first)
allItems.sort((a, b) => b.relevanceScore - a.relevanceScore);

// Pick from top 5 most relevant (with slight randomness)
const topItems = allItems.slice(0, 5);
const randomIndex = Math.floor(Math.random() * topItems.length);
const selected = topItems[randomIndex];

return [{ json: selected }];

