const aiResponse = $input.first().json;
const originalItem = $('Has Content?').first().json;

let postText = aiResponse.message?.content || aiResponse.text || '';

// Clean up any AI artifacts
postText = postText
  .replace(/^(Here's the post:|Post:|LinkedIn Post:|Here's a LinkedIn post:|Here is|Here's your|Here's the viral)/gi, '')
  .replace(/```/g, '')
  .trim();

// Validate
const wordCount = postText.split(/\s+/).filter(w => w.length > 0).length;

if (wordCount < 30 || !postText) {
  return [];
}

// Create simple hash
const simpleHash = postText.slice(0, 50).replace(/[^a-zA-Z0-9]/g, '').toLowerCase() + '_' + wordCount;

return [{
  json: {
    date_added: new Date().toISOString(),
    source_feed: originalItem.source || 'Unknown',
    original_topic: originalItem.title || '',
    content_hash: simpleHash,
    linkedin_post: postText,
    word_count: wordCount,
    relevance_score: originalItem.relevanceScore || 0,
    approval_status: '',
    posted_status: 'No',
    posted_time: '',
    linkedin_post_id: ''
  }
}];

const allPosts = $input.all();

// Find posts that are Approved but not yet Posted
const approvedNotPosted = allPosts.filter(post => {
  const status = (post.json.approval_status || '').toLowerCase().trim();
  const posted = (post.json.posted_status || '').toLowerCase().trim();
  const hasPost = post.json.linkedin_post && post.json.linkedin_post.length > 20;

  return status === 'approved' && posted !== 'yes' && hasPost;
});

if (approvedNotPosted.length === 0) {
  return []; // Nothing to post
}

// Get the first (oldest) approved post
const postToPublish = approvedNotPosted[0];

return [{
  json: {
    ...postToPublish.json
  }
}];

const linkedInResponse = $input.first().json;
const postData = $('Has Approved Post?').first().json;

return [{
  json: {
    content_hash: postData.content_hash,
    posted_status: 'Yes',
    posted_time: new Date().toISOString(),
    linkedin_post_id: linkedInResponse.id || linkedInResponse.updateKey || 'posted-' + Date.now()
  }
}];
